" Managed RAP (greenfield entity)
managed implementation in class ZBP_Employee unique;
define behavior for ZI_Employee
persistent table zemployee  " Framework writes here
lock master
{
  create; update; delete;  " Framework handles these
  validation checkAge on save { field BirthDate; }
}
" Developer only implements: checkAge method

" Unmanaged RAP (BAPI wrapping)
unmanaged implementation in class ZBP_MatDoc unique;
define behavior for ZI_MatDoc
{  " No persistent table — developer manages
  create;
}
" Developer implements: create method that calls BAPI
METHOD create FOR MODIFY ...
  CALL FUNCTION 'BAPI_GOODSMVT_CREATE' ...
ENDMETHOD.

" BDEF with full draft setup
managed implementation in class ZBP_PurchOrder unique;
with draft;
define behavior for ZI_PurchOrder alias PurchOrder
persistent table zpurch_order    " Active data
draft table zdt_purch_order      " Draft data (separate)
lock master
etag master LastChangedAt       " For optimistic locking
{
  create; update; delete;
  field ( readonly ) OrderId, CreatedAt;

  draft action Edit;             " Enter edit/draft mode
  draft action Activate;         " Draft -> Active record
  draft action Discard;          " Abandon draft
  draft action Resume;           " Resume existing draft
  draft determine action Prepare;" Validate before activate

  association _Items { create; with draft; }
}
" Fiori auto-saves to draft table as user types
" Activate button creates/updates active record
" Discard button removes draft without affecting active

" BOPF Approach (deprecated):
" /BOBF/IF_FRW_CONFIGURATION implement karo
" Separate classes:
" - ZCL_BOPF_PO_NODE       (node definition)
" - ZCL_BOPF_PO_ACTION     (action handler)
" - ZCL_BOPF_PO_VALIDATION (validation handler)
" Manual SEGW service: entity types, properties, associations
" Total artifacts: 5-12 classes + SEGW project

" RAP Approach (current):
" One BDEF file covers everything:
managed implementation in class ZBP_PurchOrder unique;
define behavior for ZI_PurchOrder
persistent table zpurch_order lock master
{
  create; update; delete;
  validation checkVendor on save { field VendorId; }
  determination calcNetAmount on modify { field Quantity, Price; }
  action approvePO result [1] $self;
}
" Total artifacts: BDEF + 1 impl class + CDS views
" OData V4 auto-generated via service binding

" Base Active Entity (ZI_ — stable, reusable)
@AccessControl.authorizationCheck: #CHECK
define root view entity ZI_SalesOrder
  as select from zsales_order
{
  key order_id   as OrderId,
      customer_id as CustomerId,
      status      as Status,
      total_amount as TotalAmount
}

" Projection Entity (ZC_ — UI-specific)
@Metadata.layer: #CUSTOMER
@UI.headerInfo: { typeName: 'Sales Order',
  title: { value: 'OrderId' } }
define root view entity ZC_SalesOrder
  provider contract transactional_ui
  as projection on ZI_SalesOrder
{
  @UI.lineItem: [{ position: 10 }]
  @UI.selectionField: [{ position: 10 }]
  key OrderId,
  @UI.lineItem: [{ position: 20 }]
      CustomerId,
  @UI.lineItem: [{ position: 30, criticality: 'StatusColor' }]
      Status
}
" Service exposes ZC_SalesOrder, not ZI_SalesOrder
